-- 스테이징: SQLite field_change_log 미러 (세로형: 변경 필드당 1행)
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS=0;
DROP TABLE IF EXISTS field_change_log;
CREATE TABLE field_change_log (
  `id` BIGINT NOT NULL AUTO_INCREMENT COMMENT '이력 PK',
  `작업지시번호` VARCHAR(128) NOT NULL COMMENT '작업지시번호',
  `필드명` VARCHAR(64) NOT NULL COMMENT '사업명|품명|품번|수량|납품일정',
  `변경내용` TEXT NULL COMMENT '제거·정규화된 변경 구간(이전-->이후 등)',
  `변경묶음_id` VARCHAR(64) NULL COMMENT '동일 저장 묶음(선택)',
  `기록시각` VARCHAR(64) NOT NULL COMMENT '기록 시각(ISO8601 UTC 등)',
  PRIMARY KEY (`id`),
  KEY `idx_fcl_wo` (`작업지시번호`),
  KEY `idx_fcl_field` (`필드명`),
  KEY `idx_fcl_batch` (`변경묶음_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci
COMMENT='필드 변경 이력(세로 스키마)';

-- 원본 행 수: 175, 아래 INSERT 수: 175


SET FOREIGN_KEY_CHECKS=1;
